<?php
namespace App\Http\Requests\Admin\Content;use Illuminate\Foundation\Http\FormRequest;
final class CombatBalanceRequest extends FormRequest{protected function prepareForValidation(){$this->merge(['defense_reduction_cap_basis_points'=>$this->basis($this->input('defense_reduction_cap_percent')),'absorb_damage_cap_basis_points'=>$this->basis($this->input('absorb_damage_cap_percent')),'total_mitigation_cap_basis_points'=>$this->basis($this->input('total_mitigation_cap_percent'))]);}public function authorize(){return true;}public function rules(){return['version'=>'required|integer|min:1','defense_reduction_cap_percent'=>'required','absorb_damage_cap_percent'=>'required','total_mitigation_cap_percent'=>'required','defense_reduction_cap_basis_points'=>'required|integer|min:1|max:9500','absorb_damage_cap_basis_points'=>'required|integer|min:0|max:9500','total_mitigation_cap_basis_points'=>'required|integer|min:1|max:9900','minimum_damage'=>'required|integer|min:1'];}private function basis($value){$text=trim((string)$value);if(!preg_match('/^(\d+)(?:\.(\d{1,2}))?$/',$text,$m))return-1;return(int)$m[1]*100+(isset($m[2])?(int)str_pad($m[2],2,'0'):0);}}
